using System;using System.Collections.Generic;
public class Program{static string Snap(SortedSet<int>s){var parts=new List<string>();bool open=false;int st=0,prev=0;foreach(int v in s){if(!open){st=prev=v;open=true;}else if(v==prev+1)prev=v;else{parts.Add("["+st+","+prev+"]");st=prev=v;}}if(open)parts.Add("["+st+","+prev+"]");return "["+string.Join(",",parts)+"]";}public static void Main(){string[]d=Console.In.ReadToEnd().Split((char[])null,StringSplitOptions.RemoveEmptyEntries);if(d.Length==0)return;int idx=0,t=int.Parse(d[idx++]);var cases=new List<string>();for(int tc=0;tc<t;tc++){int ops=int.Parse(d[idx++]);var seen=new SortedSet<int>();var snaps=new List<string>();for(int i=0;i<ops;i++){string op=d[idx++];if(op=="A")seen.Add(int.Parse(d[idx++]));else snaps.Add(Snap(seen));}cases.Add("["+string.Join(",",snaps)+"]");}Console.Write(string.Join("\n\n",cases));}}
